const sounds = {
  correct: new Audio('./sounds/correct.mp3'),
  wrong: new Audio('./sounds/error.mp3'),
  win: new Audio('./sounds/win.mp3'),
  play: new Audio('./sounds/start.mp3'),
  click: new Audio('./sounds/click.wav'),
  hover: new Audio('./sounds/hover.mp3'),
  ambient: new Audio('./sounds/ambient.wav')
};

if (!sounds.click.src || sounds.click.src === '') {
  sounds.click = new Audio('https://assets.mixkit.co/sfx/preview/mixkit-select-click-1109.mp3');
}
if (!sounds.hover.src || sounds.hover.src === '') {
  sounds.hover = new Audio('https://assets.mixkit.co/sfx/preview/mixkit-soft-click-1110.mp3');
}

Object.values(sounds).forEach(s => { 
  if (s) { 
    s.load(); 
    s.volume = 0.3; 
  } 
});

sounds.ambient.volume = 0.15;
sounds.ambient.loop = true;

let soundEnabled = true;
let animationFrameId;
let currentCategory = "random";
let ranking = [];
let audioContext = null;
let isUserInteracted = false;
let ambientTimeout = null;
let ambientStarted = false;

function initAudio() {
  if (!audioContext) {
    audioContext = new (window.AudioContext || window.webkitAudioContext)();
    if (audioContext.state === 'suspended') {
      audioContext.resume();
    }
  }
  return audioContext;
}

function forcePlayAmbient() {
  if (!soundEnabled) return;
  if (ambientStarted) return;
  
  initAudio();
  const s = sounds.ambient;
  if (s) {
    s.currentTime = 0;
    s.play().then(() => {
      ambientStarted = true;
      console.log('Som ambiente iniciado!');
    }).catch((err) => {
      console.log('Falha ao iniciar som ambiente:', err);
      setTimeout(forcePlayAmbient, 1000);
    });
  }
}

function handleUserInteraction() {
  if (!isUserInteracted) {
    isUserInteracted = true;
    const ctx = initAudio();
    if (ctx && ctx.state === 'suspended') {
      ctx.resume();
    }
    if (soundEnabled && !ambientStarted) {
      clearTimeout(ambientTimeout);
      ambientTimeout = setTimeout(forcePlayAmbient, 100);
    }
  }
}

