playBtn.addEventListener('click', function() {
  handleUserInteraction();
  
  const diffBtn = document.querySelector('.home-diff-options button.active');
  const catBtn = document.querySelector('.home-category-options button.active');
  
  let hasError = false;
  let errorMessage = '';
  
  if (!catBtn) {
    hasError = true;
    errorMessage = 'Selecione uma categoria!';
  } else if (!diffBtn) {
    hasError = true;
    errorMessage = 'Selecione uma dificuldade!';
  }
  
  if (hasError) {
    showToast(errorMessage, '⚠');
    return;
  }
  
  stopAmbientSound();
  
  const s = sounds.play;
  if (s && soundEnabled) {
    s.currentTime = 0;
    s.volume = 0.4;
    s.play().catch(() => {});
  }
  
  const difficulty = diffBtn.dataset.diff;
  currentCategory = catBtn.dataset.cat;
  
  const queryParams = new URLSearchParams({
    difficulty: difficulty,
    category: currentCategory
  });
  
  setTimeout(() => {
    window.location.href = 'GameScreen.html?' + queryParams.toString();
  }, 400);
});

